sql.if:
AND EXISTS (
    SELECT 1 FROM equipment_booking_items x
    WHERE x.equipment_booking_id = eb.id AND x.equipment_id = #{equipmentId}
)

mapper.select:
SELECT DISTINCT eb.id, eb.user_id, eb.borrow_date, eb.time_slots, eb.status, eb.purpose, eb.contact_info, eb.related_venue_booking_id, eb.reviewed_by, eb.reviewed_at, eb.version, eb.created_at, eb.updated_at FROM equipment_bookings eb INNER JOIN equipment_booking_items ebi ON ebi.equipment_booking_id = eb.id WHERE eb.status = 1 AND eb.id != #{approvedBookingId} AND eb.borrow_date = #{borrowDate} AND (eb.time_slots & #{timeSlots}) != 0 AND ebi.equipment_id IN
#{equipmentId}
ORDER BY eb.created_at ASC
